import React from 'react';
import { useState } from 'react-redux';
import { loadStripe } from "@stripe/stripe-js";
import { Elements } from "@stripe/react-stripe-js";
import StripeCheckout from 'react-stripe-checkout';
import axios from 'axios';

const stripePromise = loadStripe('pk_test_51LJLxKHat1IclGpV702ENq1hq2LX4RyEUKN1PWgJgSlpuSKqsYDxZmxtOAChssdKaiKcm2axN3ewPhSaTe3mRstf00pZEJW2BT');
    
const StripeCheckoutButton = ({ price }) => {
    const [ clientSecret, useClientSecret ] = useState('');
    const stripePrice = price * 100;
    
    const onToken = token => {
        axios.post('/payment', {
            items: JSON.stringify({
                amount: stripePrice,
                token
            })
        })
        .then( response => {
            alert('Payment Successful!')
        })
        .catch( error => {
            console.log('Payment error: ', error.response);
            alert(
                "There was an issue with your payment. Please check that you are using the provided credit card."
            )
        })
    };

    const appearance = { theme: 'stripe' };
    const options = { clientSecret, appearance }
    
    return(
    <StripeCheckout
        label='Pay Now'
        name='CRWN Clothing Ltd.'
        billingAddress
        shippingAddress
        image='https://sendeyo.com/up/d/f3eb2117da'
        description={`Your total is $${price}`}
        amount={stripePrice}
        panelLabel='Pay Now'
        token={onToken}
        stripe={stripePromise}
    />
    );
};

export default StripeCheckoutButton;
